var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오, 오르카! 괜찮아?","JPN":"オ、オルカ！　大丈夫？","ENG":"O-Orca! Are you alright?","TWN":"奧、奧爾卡！妳沒事吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그 거대한 녀석은 어떻게 된 거야?","JPN":"あの巨大な奴はどうなったんだ？","ENG":"What happened to that giant thing?","TWN":"那個巨大的傢伙怎麼了？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"조금 전에 뭔가가 날아와서 채간 것처럼 보였는데?","JPN":"さっき飛んできた何かにさらわれたようだが？","ENG":"Didn't something swoop down and snatch it away?","TWN":"剛剛好像有什麼東西飛了過來，把它給抓走的樣子？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L9_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......괜찮으니까 호들갑 떨지 마라, 인간.","JPN":"……いいから騒ぐな、人間。","ENG":"I'm fine. Stop making noise, human.","TWN":"……夠了，不要大驚小怪，人類。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그나저나 다 잡아놓은 먹잇감을 가로채이다니......","JPN":"しかし、ほぼ仕留めた獲物を横取りされるとはな……","ENG":"I can't believe I let my prey get taken away.","TWN":"竟然把我抓到的獵物給搶走了……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이래서야 힘만 소모하고 손해가 크군.","JPN":"これじゃ、体力を消耗しただけで、損失が大きいな。","ENG":"What a waste of effort.","TWN":"這樣只會消耗力氣，增加損失而已。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 인간!","JPN":"おい、人間！","ENG":"Hey, human!","TWN":"喂，人類！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐? 나, 날 부른 거야?","JPN":"え？　お、俺のこと？","ENG":"Huh? M-me?","TWN":"什麼？妳、妳在叫我嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그래. 너 말이다.","JPN":"そうだ、お前のことだ。","ENG":"Yes, you.","TWN":"沒錯。就是你。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금부터 난 힘을 회복하기 위해 한동안 잠들 거다.","JPN":"これから私は体力回復のためにしばらく眠りにつくつもりだ。","ENG":"I'm going to be asleep for a while to recover strength.","TWN":"我現在要恢復力量，會暫時間陷入沉睡。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그러니까 그동안 이 몸을 잘 관리하도록. 이건 이제 소중한 내 몸이니까.","JPN":"だからその間、この体を守ってくれ。今後ともこれは、私の大切な体だからな。","ENG":"Make sure you take care of my body until I come back. This is mine now.","TWN":"所以你給我在這段時間好好管理這個身體，因為這個身體現在是我的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐? 다짜고짜 무슨 소릴......?","JPN":"いきなり何言ってんだ……？","ENG":"Huh? What are you talking about?","TWN":"什麼？妳突然說些什麼……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L24_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"오, 오르카!","JPN":"オ、オルカ！","ENG":"O-Orca!","TWN":"奧、奧爾卡！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......찰리?","JPN":"……チャーリー？","ENG":"Charlie?","TWN":"……查理？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"정신이 돌아온 거야, 오르카? 우릴 알아보겠어?","JPN":"意識が戻ったのか、オルカ？　俺らのこと、わかるか？","ENG":"Are you back, Orca? Do you recognize us?","TWN":"妳回過神來了嗎，奧爾卡？妳認得出我們了嗎"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"당연히...... 알아본다...... 찰리, 그리고 제시카......","JPN":"もちろん……わかる……チャーリー、ジェシカ……","ENG":"Of course... I recognize you... Charlie, Jessica...","TWN":"當然……認得出來……查理，還有潔西卡……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L33_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"오르카...... 그럼 이제 괜찮은 거야?","JPN":"オルカ……大丈夫なの？","ENG":"Orca... Are you really back for good?","TWN":"奧爾卡……所以妳現在沒事了嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"난 너랑 그...... <color=#ffd34c>오르카</color>가 완전히 뒤바뀐 거라고 생각했는데......","JPN":"私はあんたとあの……<color=#ffd34c>オルカ</color>が完全に入れ替わったと思って……","ENG":"I thought that <color=#ffd34c>other Orca</color> took over your body forever.","TWN":"我以為妳和那個……<color=#ffd34c>奧爾卡</color>完全調換了呢……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L38_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"지금 난 <color=#ffd34c>오르카</color>가 잠시 잠든 사이에 의식의 수면으로 떠오른 것뿐이야......","JPN":"今の私は、<color=#ffd34c>オルカ</color>が眠りについた間に、\\n別の意識として浮上してきただけだよ……","ENG":"I came above the barrier of consciousness because <color=#ffd34c>Orca</color> went to sleep.","TWN":"現在我只是在<color=#ffd34c>奧爾卡</color>暫時睡著的時候，浮出意識的水面而已……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"힘을 빌리는 대신...... 육체의 주도권은 오르카에게 넘겼으니까......","JPN":"力を借りる代わりに……肉体の主導権はオルカに渡したから……","ENG":"In return for her strength, I agreed to let her take control of my body.","TWN":"借助力量的同時……肉體的主導權就會交給奧爾卡……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L40_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"뭐? 그, 그런......!","JPN":"なっ？　そ、そんな……！","ENG":"You what? B-but...","TWN":"什麼？怎、怎麼會……！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>오르카</color>가 원하면 언제든지 몸을 넘겨줘야 해.","JPN":"<color=#ffd34c>オルカ</color>の望み次第で、いつでも体を渡さなければならないの。","ENG":"I have to let <color=#ffd34c>Orca</color> take over whenever she wants.","TWN":"不管什麼時候，只要<color=#ffd34c>奧爾卡</color>想要，就要把身體交給他。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"그게...... 계약이니까.......","JPN":"そういう……約束だから……","ENG":"That was the deal...","TWN":"那是……我們的契約……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"알았어. 그래도 일단 지금은 괜찮은 거지?","JPN":"わかった。でも、今はとりあえず大丈夫なのね？","ENG":"I see. You're saying you're fine now, aren't you?","TWN":"知道了。但現在暫時沒事了吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ORCA_RSEVEN_NULL_NULL","text":{"KOREA":"응......","JPN":"うん……","ENG":"Yes...","TWN":"嗯……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"어- 이!","JPN":"おーい！","ENG":"Hey!","TWN":"喂！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L1_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"저건......?","JPN":"あれは……？","ENG":"That's...","TWN":"那是……？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"메이슨 형씨! 이쪽이야, 이쪽!!","JPN":"メイソン！　こっちだよ、こっち！！","ENG":"Mason! Over here!","TWN":"梅森大哥！這邊啊，這邊！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......다행이군, 살아있어서.","JPN":"……よかった、生きててくれて。","ENG":"Good to see you all alive.","TWN":"……真是太好了，你們還活著。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"일단은 모두 무사한 것 같은데...... 다친 곳은 없나?","JPN":"とりあえず全員無事のようだが……ケガはないか？","ENG":"You seem intact, at least in appearance. Are you hurt anywhere?","TWN":"姑且看起來都沒事……沒有受傷嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그럭저럭.","JPN":"なんとか。","ENG":"We're fine, more or less.","TWN":"算是吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그런데 형씨는 꼴이 말이 아닌걸?","JPN":"そんなお前さんこそ、ひでえ格好してるじゃないか。","ENG":"But you look terrible.","TWN":"但是大哥你也太不像話了吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"지금도 부축 받아서 온 것 같은데 괜찮은 거 맞아?","JPN":"自力ではまともに歩けないようだが、大丈夫なのか？","ENG":"You can't even walk on your own. Are you sure you're okay?","TWN":"就是現在也是被別人攙扶著，你真的沒事嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"뭐...... 좀 긁히긴 했지.","JPN":"まあ……かすり傷だ。","ENG":"Meh, they're nothing but scratches.","TWN":"這……稍微被抓了幾道傷口而已。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"허세부리는 건 무슨 메이슨 집안 유전병 같은 건가?","JPN":"まったく、兄弟そろって強がりだなんて、メイソン家の遺伝子に組み込まれてるわけ？","ENG":"Is being full of it some kind of behavioral disorder that runs in your family?","TWN":"耍帥是梅森家族的遺傳疾病嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그런 이야기는 제대로 걸을 수 있고 난 후에나 하라고.","JPN":"そんな話はまともに歩けるようになってからしなさいよ。","ENG":"Say that when you're well enough to stand up straight.","TWN":"這種話等你自己能走了再說吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그래도 경찰 나리들이 늦지 않게 합류해 줘서 이 정도로 끝난 거야.","JPN":"……これでも警察組がタイミング良く現れてくれたから、これだけで済んだんだ。","ENG":"Things could have been much worse if the police ladies hadn't joined us in time.","TWN":"但多虧警察大人們有及時和我們會合，我才能只受這樣的小傷就了事。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"안 그랬으면 이렇게 다시 만날 일도 없었겠지.","JPN":"それがなければ、こうやって再会できなかっただろうな。","ENG":"Otherwise, we wouldn't be meeting here again.","TWN":"不然我們就不會再見面了吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"하하, 저희도 위기일발이긴 했죠.","JPN":"はは、私たちも危機一髪の状況だったんですよ。","ENG":"Hah hah, we barely escaped being killed ourselves.","TWN":"哈哈，我們也是千鈞一髮啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"리플레이서 나이트가 갑자기 사라지지 않았다면 도우러 갈 수 없었을 거에요.","JPN":"リプレイサー・ナイトが急に消えてくれなかったら、助けにいけなかったでしょうね。","ENG":"We wouldn't have been able to go help you if the Replacer Knight hadn't disappeared all of a sudden.","TWN":"要不是克隆．騎士突然消失，我們也沒辦法去幫忙你們。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"......그보다 묻고 싶은 게 있습니다.","JPN":"……それより、聞きたいことがあります。","ENG":"About that, I'd like to ask everyone something.","TWN":"……話說我有個問題想問。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위가 말씀드린 대로, 리플레이서 나이트뿐만 아니라 다른 병력들 역시 교전 중인 상황임에도 불구하고 급하게 철수해 버렸습니다.","JPN":"マエカワ警部補の言うとおり、リプレイサー・ナイトだけでなく、\\n他の兵力も交戦中だったにもかかわらず急に撤退してしまいました。","ENG":"Like Lieutenant Kang said, the Replacer Knight fell back, and it seems all other forces that were engaged in combat did the same thing.","TWN":"就像姜素英警衛說的那樣，不只有克隆．騎士，就連其他部隊也不管當前的狀況，急忙地撤退了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"아무래도 조금 전 이쪽으로 날아간 리플레이서 퀸과 관련이 있는 것 같은데......","JPN":"どうも先ほどこちらへ飛んでいったリプレイサー・クイーンと、何らかの関係がありそうでしたが……","ENG":"I assume it has something to do with the Replacer Queen flying in this direction.","TWN":"這似乎和剛剛飛過來的克隆．女皇有關的樣子……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"혹시 짐작 가는 바가 있으신가요?","JPN":"何か心当たりはありますか？","ENG":"Does anyone have different guesses?","TWN":"你們心裡有什麼底嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"그, 글쎄? 조금 전에 뭔가가 날아오긴 했는데 그게 리플레이서 퀸이었나?","JPN":"さ、さあ？　さっき何かが飛んできたようだが、あれがリプレイサー・クイーンだったのか？","ENG":"Well, something did fly by a while back, but I'm not sure it was the Replacer Queen.","TWN":"這個嘛？剛剛飛過來的那是克隆．女皇嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"너무 빨라서 자세히 보진 못했어.","JPN":"速すぎてちゃんと観察できなかったのよ。","ENG":"It happened so quickly.","TWN":"太快了我沒看清楚。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"하지만 그 녀석이 우리가 싸우던 괴물을 독수리처럼 잡아채서 저쪽으로 날아간 건 사실이야.","JPN":"だけど、私たちと戦っていたバケモノを、そいつがかっさらって向こうに飛んでいったのは事実よ。","ENG":"But whatever it was, it snatched the monster we were fighting and flew away.","TWN":"但那個人像老鷹一樣，把和我們戰鬥的怪物抓走了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"그랬군요.","JPN":"なるほど。","ENG":"I see.","TWN":"這樣啊。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"전투 중이던 병력과 간부들을 빼서 총동원할 정도로 급한 일이라니......","JPN":"戦闘中の兵力や幹部らに招集をかけるほどの緊急事態か……","ENG":"Why did they have to pull out their forces from ongoing combat so hastily?","TWN":"竟然會緊急到把戰鬥中的兵力和幹部調回……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"역시 <color=#ffd34c>저게</color> 나타난 것 때문인 걸까요?","JPN":"やっぱり<color=#ffd34c>あれ</color>が現れたせいでしょうか？","ENG":"Was it because of <color=#ffd34c>that ship</color>?","TWN":"果然是因為<color=#ffd34c>那個</color>出現了嗎？"},"stage":{"bg":"MAINSTREAM_5405010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"태스크포스 1 엔터프라이즈.","JPN":"タスクフォース1エンタープライズ。","ENG":"The Enterprise of TASKFORCE 1...","TWN":"特遣勢力1企業號。"},"stage":{"bg":"MAINSTREAM_5405010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"대정화 전쟁을 승리로 이끈 전설적인 함선이지.","JPN":"大浄化戦争を勝利に導いた、レジェンド級の艦船だ。","ENG":"The legendary ship that led the Grand Purification War to victory.","TWN":"那是將淨化之戰引向勝利的傳說艦船。"},"stage":{"bg":"MAINSTREAM_5405010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"전쟁 후에 노후화와 재개장을 이유로 일시 퇴역했다고 들었는데......","JPN":"戦後、老朽化対策や再改装のためにいったんは退役したと聞いたが……","ENG":"I heard its parts were aging, so it temporarily went out of service for remodeling after the war.","TWN":"聽說那艘艦船在戰爭後，因為老化和重啟的理由暫時退役了……"},"stage":{"bg":"MAINSTREAM_5405010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"저걸 끌어오다니 블랙 버드 양반도 꽤 무리를 했나 보군.","JPN":"あれを引っ張り出すとは、ブラックバードさんも相当無理したんだろうな。","ENG":"Blackbird must have pulled some strings, seeing that he was able to bring that ship all the way here.","TWN":"竟然把那個給拖過來了，黑鳥也真是大費周章呢。"},"stage":{"bg":"MAINSTREAM_5405010","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이제 어쩔 거야?","JPN":"これからはどうするの？","ENG":"So what now?","TWN":"那現在要怎麼辦？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"원래 목표는 달성했어. 뉴 오하이오는 대파됐고 관리국 연합함대도 끌어들였으니까......","JPN":"元々の目的は達成したわよ。\\nニューオハイオは大破、管理局の連合艦隊も引き込んだ。","ENG":"Our goal is accomplished. New Ohio's down, and we got the Administration Coalition Fleet involved.","TWN":"原來的目標已經完成了。新俄亥俄被破壞，管理局的聯合艦隊也叫來了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L45_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"우리 일은 끝난 셈이지.","JPN":"アタシたちの仕事は終わったも同然よね。","ENG":"There's nothing left for us to do.","TWN":"我們的工作已經結束了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"이대로 여기 죽치고 앉아 있다가 구조선을 타도 되겠지만......","JPN":"このままここに留まって救助船を待っても良いでしょうけど……","ENG":"We can sit around here until the rescue ship arrives...","TWN":"我們現在就坐在這裡，等著坐上救援艦船就行了，但是……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......역시 그렇게 둘 순 없겠지?","JPN":"……やっぱりそういうわけにはいかないよな？","ENG":"But... that's wouldn't be very responsible of us, right?","TWN":"……果然沒辦法置之不理吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그야...... 일을 시작했으면 끝까지 가보는 게 내 성미랑 맞긴 하지.","JPN":"まあ……一度始めたら最後まで完遂する、それがアタシの主義ではあるけど。","ENG":"Well, I always follow through with what I've started.","TWN":"因為啊……工作一旦開始就要做到最後，這才是我的風格。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아. 그럼 원하는 사람들만이라도 가자고.","JPN":"よし、だったら希望するメンバーだけでも行ってみよう。","ENG":"Good then. Anyone who wants in, you're welcome to join us.","TWN":"好吧。只要想來的人跟來就行了。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"중간에 헤어진 친구들도 찾아야 하고......","JPN":"途中ではぐれてしまった仲間も探さないとならんし……","ENG":"We have friends who parted ways and are now waiting to be found.","TWN":"我還得去找中途和我們分開的朋友……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"어쩌면 저쪽에서도 <color=#ffd34c>작은 도움의 손길</color>이 필요할지도 모르잖아?","JPN":"ひょっとすると、向こうも<color=#ffd34c>小さな協力</color>が必要かもしれないしな？","ENG":"And who knows? Our allies may need a <color=#ffd34c>little helping hand</color>.","TWN":"說不定那邊也需要<color=#ffd34c>小小的幫助</color>呢？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"엔터프라이즈의 주력 소대라면 역시 델타 세븐이겠지.","JPN":"エンタープライズの主力小隊といえば、デルタセブンよね。","ENG":"Ah, Delta Seven must be the main platoon of the Enterprise.","TWN":"企業號的主力小隊果然是第七三角洲部隊吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"JANE_MASON_NULL_NULL","text":{"KOREA":"그 콧대 높은 양반들에게 빚을 지울 수 있다니, 그거 참 마음에 드는걸?","JPN":"あのお偉いさんたちに貸しを作れるだなんて、おいしい話ね。","ENG":"It'd be awesome if we could make those snobby folks owe us something.","TWN":"要欠那些目中無人的傢伙人情，我怎麼可能會想要呢？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JANE_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"으윽......","JPN":"ううっ……","ENG":"Hngh...","TWN":"唔呃……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"TOMY_MASON_NULL_NULL","text":{"KOREA":"제리! 괜찮아? 총 맞은 데는 좀 어때?","JPN":"ジェリー！　大丈夫か？　撃たれたところはどうだ？","ENG":"Jerry! You alright? How does it look where you got shot?","TWN":"傑瑞！你還好吧？被槍打到的地方怎麼樣了？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"아파 뒈질 것 같긴 한데. 방아쇠 당기는 데는 문제 없어.","JPN":"死ぬほど痛てぇが、引き金を引く分には問題ないぜ。","ENG":"It hurts like hell, but I have no problem pulling my trigger.","TWN":"痛到不行。但要扣扳機還是沒問題的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"그보다 메이슨 저 녀석, 자꾸 죽을 자리로 뛰어드는데 안 따라갈 수도 없고......","JPN":"それよりメイソンの野郎、性懲りもせず火中に飛び込みやがって。\\nついていかないわけにもいかねえし……","ENG":"Mason, that crazy bastard is almost suicidal. And we can't just let him go alone...","TWN":"話說梅森那個傢伙，總是往死裡衝，要跟也跟不上……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"환장하겠네, 진짜.","JPN":"まいったぜ、本当に。","ENG":"This is driving me nuts, really.","TWN":"瘋了啊，真的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MICKEY_MASON_NULL_NULL","text":{"KOREA":"뭐...... 그쪽 연락책은 메이슨이 맡고 있으니까 죽으면 곤란하지.","JPN":"まあ……こっちの連絡係はメイソン担当だから、死んでもらったら困るしな。","ENG":"Well, we need him alive; he's the one in charge of making contacts.","TWN":"呃……那你的聯絡窗口就交給梅森了，你要是死了會很麻煩的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"하아...... 가자, 가! 어차피 총알구멍 하나 뚫리나 두 개 뚫리나 별 차이 없겠지.","JPN":"はあ……行くしかねえか！　一発撃たれようが二発撃たれようが、大して変わんねえからな。","ENG":"*Sigh* Okay! Let's just go. I wouldn't mind a few more holes in my body.","TWN":"唉……走吧，走！反正彈孔多一個兩個也有沒什麼太大的區別。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JERRY_MASON_NULL_NULL","text":{"KOREA":"살아남으면 성과급이나 두둑하게 챙겨달라고!","JPN":"もし生き残れたら、報酬をたっぷり上乗せしろよな！","ENG":"I'll kill you if you get cheap with me about my incentives!","TWN":"要是我活下來的話，我就多拿點績效獎金吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"JERRY_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TOMY_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MICKEY_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"내키진 않지만...... 그 괴물로 변한 사장 녀석은 확실히 처리해 둬야 후환이 없겠지.","JPN":"気は進まないけど……バケモノになったあの社長だけは、息の根を止めてやらなきゃ。","ENG":"I hate to say this, but we'll have to take care of that president-monster to prevent future trouble.","TWN":"雖然不太樂意……但我們得把那個變成怪物的老闆確實處理掉，不然會後患無窮的。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"우리도 간다.","JPN":"私たちも同行するわ。","ENG":"We're going too.","TWN":"我們也去吧。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ORCA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"YUMI_POLICE_NULL_NULL","text":{"KOREA":"강소영 경위......","JPN":"マエカワ警部補……","ENG":"Lieutenant Kang.","TWN":"姜素英警衛……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"SOYEONG_POLICE_NULL_NULL","text":{"KOREA":"네이 네이, 그렇게 병아리 같은 눈으로 안 바라보셔도 돼요. 가자고요, 경정님.","JPN":"はいはい、そんなウルウルした目で見なくてもわかってますよ。行きましょう、警視様。","ENG":"Sure, sure. You don't have to give me that desperate look. Let's go, Major.","TWN":"好啦好啦，不要用小雞一樣的眼睛看我啦。走吧，警正。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOYEONG_POLICE_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YUMI_POLICE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"좋아. 그럼 다들 출발하자고!","JPN":"よし。それじゃあ、みんな出発だ！","ENG":"Alright. Let's move out, everyone.","TWN":"好，那大家出發吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"자, 잠깐! 우리한텐 왜 안 물어봐요! 우리 의견도 물어봐 달라고요!","JPN":"ちょ、ちょっと！　秋たちの意見は？　秋たちにも聞いてくださいよ！","ENG":"W-wait! Why isn't anyone asking our opinions? We don't feel comfortable being neglected like this!","TWN":"等、等等！怎麼不問我們啊！也要問問我們的意見啊！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L31_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"이런 게...... 강제진행 컷신이라는 거군요...... 역시 자유도 따윈 환상인 거겠죠......","JPN":"これは……言わずとも察しろのカットシーン……やっぱり自由なんて、幻なんです……","ENG":"Ah... This must be one of those forced cutscenes... Nonlinear gameplay is nothing but a fantasy...","TWN":"這種事情……就是強制進行的劇情畫面吧……果然自由度什麼的都是幻想……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}}]`);export{e as default};